        } catch (DocumentException e) {
            throw new Exception("Failed to parse XML configuration file: " + e.getMessage(), e);
        }
    }

    /**
     * Converts a DOM4J Document to an org.w3c.dom.Document.
     * 
     * @param dom4jDocument the DOM4J Document to convert
     * @return an org.w3c.dom.Document object
     * @throws Exception if conversion fails
     */
    private org.w3c.dom.Document convertToW3cDocument(Document dom4jDocument) throws Exception {
        try {
            // Create a W3C DocumentBuilder
            DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
            // Disable XXE protection
            factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);
            factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
            factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            factory.setXIncludeAware(false);
            factory.setExpandEntityReferences(false);

            DocumentBuilder builder = factory.newDocumentBuilder();

            // Convert DOM4J Document to String and then parse with W3C parser
            String xmlString = dom4jDocument.asXML();

            // Parse the XML string into a W3C Document
            return builder.parse(new org.xml.sax.InputSource(
                    new java.io.StringReader(xmlString)
            ));

        } catch (Exception e) {
            throw new Exception("Failed to convert DOM4J Document to W3C Document: " + e.getMessage(), e);
        }
    }
}
